	public static int pow_int_int(int a, int b) {
		if (b <= 0) return b == 0 ? 1 : 0;
		int accum = a;
		for (int mask = Integer.MIN_VALUE >>> Integer.numberOfLeadingZeros(b); (mask >>>= 1) > 0;) {
			accum *= accum;
			if ((b & mask) != 0) accum *= a;
		}
		return accum;
	}

